chat_histories: dict = {}

ICONS = {"قراءة":"📖","بلاغة":"🌸","أدب":"📜","نصوص":"📝","نحو":"🔤","تعبير":"💬","قصة":"📚","مزيج":"🎯"}

WELCOME = (
    "🎓 *أهلاً بك في بوت اللغة العربية*\n"
    "━━━━━━━━━━━━━━━━━━━━━━\n"
    "📚 ثاني ثانوي | ترم ثانٍ 2026\n"
    "📖 سلسلة *الامتحان المتميزون*\n"
    "━━━━━━━━━━━━━━━━━━━━━━\n"
    "💡 اكتب سؤالك مباشرةً أو اختر من القائمة:"
)

def main_kb() -> InlineKeyboardMarkup:
    return InlineKeyboardMarkup([
        [InlineKeyboardButton("📋 الملخصات",callback_data="sum_menu"),
         InlineKeyboardButton("❓ بنك الأسئلة",callback_data="q_menu")],
        [InlineKeyboardButton("🎯 اختبار عشوائي",callback_data="quiz_random"),
         InlineKeyboardButton("📊 المواد",callback_data="subjects")],
        [InlineKeyboardButton("ℹ️ عن البوت",callback_data="about")],
    ])

def back_kb(cat: str, menu: str = "sum_menu") -> InlineKeyboardMarkup:
    """زر رجوع مع الرئيسية"""
    return InlineKeyboardMarkup([
        [InlineKeyboardButton(f"🔙 رجوع",callback_data=f"sum_cat_{cat}"),
         InlineKeyboardButton("📋 الملخصات",callback_data=menu)],
        [InlineKeyboardButton("🏠 الرئيسية",callback_data="main")],
    ])

async def start(update: Update, context: ContextTypes.DEFAULT_TYPE) -> None:
    await update.message.reply_text(WELCOME, parse_mode="Markdown", reply_markup=main_kb())

async def button(update: Update, context: ContextTypes.DEFAULT_TYPE) -> None:
    q = update.callback_query
    await q.answer()
    d = q.data

    if d == "main":
        await q.edit_message_text(WELCOME, parse_mode="Markdown", reply_markup=main_kb())

    elif d == "new_chat":
        uid = update.effective_user.id
        chat_histories.pop(uid, None)
        await q.edit_message_text(
            "✅ تم بدء محادثة جديدة!\nاكتب سؤالك الآن 👇",
            reply_markup=InlineKeyboardMarkup([[
                InlineKeyboardButton("🏠 الرئيسية", callback_data="main")
            ]]))

    elif d == "about":
        total_q = sum(len(v) for v in QUESTIONS.values())
        total_s = len(SUMMARIES)
        await q.edit_message_text(
            f"ℹ️ *عن البوت*\n━━━━━━━━━━━━━━━━━━━━━━\n"
            f"🤖 @Arabic_Sec2Q_bot\n"
            f"🎓 ثاني ثانوي - ترم ثانٍ 2026\n"
            f"📖 سلسلة الامتحان المتميزون\n\n"
            f"✨ *المحتوى:*\n"
            f"• {total_s} ملخصاً شاملاً\n"
            f"• {total_q} سؤالاً بالإجابات\n"
            f"• تقييم فوري مع الشرح\n"
            f"• مساعد ذكي (أستاذ كريم 😄)",
            parse_mode="Markdown",
            reply_markup=InlineKeyboardMarkup([[
                InlineKeyboardButton("🏠 الرئيسية", callback_data="main")
            ]]))

    elif d == "subjects":
        kb = []
        for cat, items in CATEGORY_MAP.items():
            icon = ICONS.get(cat, "📚")
            kb.append([InlineKeyboardButton(
                f"{icon} {cat} ({len(items)} ملخصاً)",
                callback_data=f"sum_cat_{cat}")])
        kb.append([InlineKeyboardButton("🏠 الرئيسية", callback_data="main")])
        await q.edit_message_text(
            "📊 *المواد الدراسية*\nاختر المجال:",
            parse_mode="Markdown",
            reply_markup=InlineKeyboardMarkup(kb))

    elif d == "sum_menu":
        kb = []
        row = []
        cats = list(CATEGORY_MAP.keys())
        for i, cat in enumerate(cats):
            icon = ICONS.get(cat, "📚")
            row.append(InlineKeyboardButton(f"{icon} {cat}", callback_data=f"sum_cat_{cat}"))
            if len(row) == 2:
                kb.append(row)
                row = []
        if row:
            kb.append(row)
        kb.append([InlineKeyboardButton("🏠 الرئيسية", callback_data="main")])
        await q.edit_message_text(
            "📋 *الملخصات*\nاختر المجال:",
            parse_mode="Markdown",
            reply_markup=InlineKeyboardMarkup(kb))

    elif d.startswith("sum_cat_"):
        cat = d.replace("sum_cat_", "")
        items = CATEGORY_MAP.get(cat, [])
        icon = ICONS.get(cat, "📚")
        kb = [[InlineKeyboardButton(name, callback_data=f"sum_show_{key}")]
              for name, key in items]
        kb.append([InlineKeyboardButton("🔙 الملخصات", callback_data="sum_menu"),
                   InlineKeyboardButton("🏠 الرئيسية", callback_data="main")])
        await q.edit_message_text(
            f"{icon} *مجال {cat}*\nاختر الملخص:",
            parse_mode="Markdown",
            reply_markup=InlineKeyboardMarkup(kb))

    elif d.startswith("sum_show_"):
        key = d.replace("sum_show_", "")
        s = SUMMARIES.get(key)
        if not s:
            await q.edit_message_text("⚠️ لم يُوجد هذا الملخص.")
            return
        # استنتاج المجال من المفتاح
        cat = key.split("_")[0]
        text = f"{s['title']}\n━━━━━━━━━━━━━━━━━━━━━━\n{s['content']}"
        if len(text) > 4000:
            text = text[:3990] + "\n...(يتبع)"
        await q.edit_message_text(
            text,
            parse_mode="Markdown",
            reply_markup=back_kb(cat))

    elif d == "q_menu":
        kb = []
        row = []
        for cat in QUESTIONS:
            icon = ICONS.get(cat, "❓")
            count = len(QUESTIONS[cat])
            row.append(InlineKeyboardButton(f"{icon} {cat} ({count})", callback_data=f"q_cat_{cat}"))
            if len(row) == 2:
                kb.append(row)
                row = []
        if row:
            kb.append(row)
        kb.append([InlineKeyboardButton("🎯 مزيج عشوائي (10)", callback_data="quiz_random")])
        kb.append([InlineKeyboardButton("🏠 الرئيسية", callback_data="main")])
        await q.edit_message_text(
            "❓ *بنك الأسئلة*\nاختر المادة:",
            parse_mode="Markdown",
            reply_markup=InlineKeyboardMarkup(kb))

    elif d.startswith("q_cat_"):
        cat = d.replace("q_cat_", "")
        qs = QUESTIONS.get(cat, []).copy()
        if not qs:
            await q.edit_message_text("⚠️ لا توجد أسئلة حالياً.")
            return
        random.shuffle(qs)
        _init(context, cat, qs)
        await _send_q(q, context)

    elif d == "quiz_random":
        all_q = [x for qs in QUESTIONS.values() for x in qs]
        random.shuffle(all_q)
        _init(context, "مزيج", all_q[:10])
        await _send_q(q, context)

    elif d.startswith("ans_"):
        chosen = d.replace("ans_", "")
        qs = context.user_data.get("qs", [])
        idx = context.user_data.get("idx", 0)
        if idx >= len(qs):
            return
        item = qs[idx]
        correct = item["answer"]
        if chosen == correct:
            context.user_data["score"] = context.user_data.get("score", 0) + 1
            res = "✅ *إجابة صحيحة!* 🎉"
        else:
            res = f"❌ *خاطئة!* الصواب: *{correct}*"
        context.user_data["idx"] = idx + 1
        score = context.user_data.get("score", 0)
        await q.edit_message_text(
            f"{res}\n\n💡 *التوضيح:*\n{item.get('explanation','')}\n\n📊 النقاط: {score}/{idx+1}",
            parse_mode="Markdown",
            reply_markup=InlineKeyboardMarkup([[
                InlineKeyboardButton("التالي ➡️", callback_data="next_q")
            ]]))

    elif d == "next_q":
        qs = context.user_data.get("qs", [])
        if context.user_data.get("idx", 0) < len(qs):
            await _send_q(q, context)
        else:
            await _result(q, context)


def _init(ctx: ContextTypes.DEFAULT_TYPE, cat: str, qs: list) -> None:
    ctx.user_data.update({"cat": cat, "idx": 0, "score": 0, "qs": qs})


async def _send_q(q, ctx: ContextTypes.DEFAULT_TYPE) -> None:
    qs = ctx.user_data.get("qs", [])
    idx = ctx.user_data.get("idx", 0)
    score = ctx.user_data.get("score", 0)
    cat = ctx.user_data.get("cat", "")
    icon = ICONS.get(cat, "❓")
    total = len(qs)
    if idx >= total:
        return
    item = qs[idx]
    filled = min(idx, 10)
    prog = "🟩" * filled + "⬜" * (min(total, 10) - filled)
    kb = [[InlineKeyboardButton(opt, callback_data=f"ans_{opt[0]}")] for opt in item["options"]]
    kb.append([InlineKeyboardButton("❌ إلغاء", callback_data="q_menu")])
    await q.edit_message_text(
        f"{icon} *اختبار {cat}*\n{prog} {idx}/{total} | نقاط: {score}\n"
        f"━━━━━━━━━━━━━━━━━━━━━━\n*س{idx+1}: {item['q']}*",
        parse_mode="Markdown",
        reply_markup=InlineKeyboardMarkup(kb))


async def _result(q, ctx: ContextTypes.DEFAULT_TYPE) -> None:
    score = ctx.user_data.get("score", 0)
    total = len(ctx.user_data.get("qs", []))
    pct = int((score / total) * 100) if total else 0
    if pct >= 90:
        grade = "🏆 ممتاز جداً"
    elif pct >= 75:
        grade = "🥇 جيد جداً"
    elif pct >= 60:
        grade = "🥈 جيد"
    elif pct >= 50:
        grade = "🥉 مقبول"
    else:
        grade = "📚 راجع الملخصات"
    bar = "🟩" * (pct // 10) + "⬜" * (10 - pct // 10)
    await q.edit_message_text(
        f"🎉 *انتهى الاختبار!*\n━━━━━━━━━━━━━━━━━━━━━━\n"
        f"✅ صحيح: *{score}/{total}*\n"
        f"📊 النسبة: *{pct}%*\n{bar}\n"
        f"🎖️ *{grade}*",
        parse_mode="Markdown",
        reply_markup=InlineKeyboardMarkup([
            [InlineKeyboardButton("🔄 اختبار جديد", callback_data="q_menu"),
             InlineKeyboardButton("📋 الملخصات", callback_data="sum_menu")],
            [InlineKeyboardButton("🏠 الرئيسية", callback_data="main")],
        ]))


async def ai_chat(update: Update, context: ContextTypes.DEFAULT_TYPE) -> None:
    """أستاذ كريم - مساعد ذكي للمنهج"""
    uid = update.effective_user.id
    user_msg = update.message.text.strip()

    kb = InlineKeyboardMarkup([
        [InlineKeyboardButton("🔄 محادثة جديدة", callback_data="new_chat"),
         InlineKeyboardButton("🏠 الرئيسية", callback_data="main")],
    ])

    if uid not in chat_histories:
        chat_histories[uid] = []

    chat_histories[uid].append({"role": "user", "content": user_msg})

    if len(chat_histories[uid]) > 12:
        chat_histories[uid] = chat_histories[uid][-12:]

    wait = await update.message.reply_text("⚡")

    try:
        client = OpenAI(api_key=OPENAI_KEY)
        resp = client.chat.completions.create(
            model="gpt-4o-mini",
            messages=[
                {"role": "system", "content": SYSTEM_PROMPT},
                *chat_histories[uid],
            ],
            max_tokens=350,
            temperature=0.6,
        )
        answer = resp.choices[0].message.content.strip()
        chat_histories[uid].append({"role": "assistant", "content": answer})
        await wait.delete()
        await update.message.reply_text(answer, reply_markup=kb)
    except Exception as e:
        logger.error(f"OpenAI error: {type(e).__name__}: {e}")
        await wait.delete()
        await update.message.reply_text(
            "⚠️ حدث خطأ في الاتصال، حاول مرة أخرى.",
            reply_markup=kb)


def main() -> None:
    if not BOT_TOKEN:
        raise ValueError("BOT_TOKEN غير موجود في environment variables!")
    if not OPENAI_KEY:
        logger.warning("OPENAI_API_KEY غير موجود - ChatGPT لن يعمل!")

    logger.info("✅ @Arabic_Sec2Q_bot يعمل الآن...")
    app = Application.builder().token(BOT_TOKEN).build()
    app.add_handler(CommandHandler("start", start))
    app.add_handler(CommandHandler("help", start))
    app.add_handler(CommandHandler("menu", start))
    app.add_handler(CallbackQueryHandler(button))
    app.add_handler(MessageHandler(filters.TEXT & ~filters.COMMAND, ai_chat))
    app.run_polling(drop_pending_updates=True)


if __name__ == "__main__":
    main()
